#include <vector>
#include <numeric>
#include <cmath>

// We use a helper class/struct for DSU implementation tailored for parity tracking
struct ParityDSU {
    std::vector<long long> parent;
    // diff[i] stores the parity of the path distance from node i to its current representative parent[i].
    // 0 means even path weight, 1 means odd path weight.
    std::vector<int> diff; 
    int N;

    ParityDSU(long long n) : N(n) {
        parent.resize(N);
        std::iota(parent.begin(), parent.end(), 0); // Initialize parent[i] = i
        diff.assign(N, 0); // Initialize distance to self as 0
    }

    // Finds the root of i, and crucially, updates diff[i] to store the path parity from i to the root.
    long long find(long long i) {
        if (parent[i] == i) {
            return i;
        }

        // Recursively find the root R and get the distance d_p from parent[i] to R.
        long long root = find(parent[i]);

        // Update path compression: 
        // The new distance diff[i] (i -> R) is (i -> parent[i]) XOR (parent[i] -> R).
        diff[i] = diff[i] ^ diff[parent[i]];

        // Set parent[i] directly to R
        parent[i] = root;

        return root;
    }

    // Attempts to unite u and v with edge weight w.
    // Returns true if the edge is added (or if it closes a consistent cycle), false otherwise.
    bool unite(long long u, long long v, int w) {
        long long root_u = find(u);
        long long root_v = find(v);

        // Path parity from u to v if they are already connected: D[u] XOR D[v]
        // (u -> R_u -> v)
        int path_parity_uv = diff[u] ^ diff[v];

        if (root_u == root_v) {
            // They are already in the same component. Adding this edge creates a cycle.
            // The cycle sum parity is (Existing Path Parity) XOR w.
            // We require the cycle sum parity to be 0 (even).
            if (path_parity_uv == w) {
                // Consistent cycle (w == D[u] XOR D[v]). Edge is added/allowed.
                return true;
            } else {
                // Inconsistent cycle (w != D[u] XOR D[v]). Edge must be rejected.
                return false;
            }
        } else {
            // They are in different components. We must merge them.
            // We merge root_v into root_u (arbitrarily chosen).

            parent[root_v] = root_u;

            // We need to set diff[root_v] = parity(R_v -> R_u).
            // Path: R_v -> v --(w)--> u -> R_u
            // Parity(R_v -> R_u) = Parity(R_v -> v) XOR w XOR Parity(u -> R_u)

            // Parity(R_v -> v) is the inverse of diff[v] (since diff[v] is v -> R_v)
            // In XOR arithmetic, inverse is itself: Parity(R_v -> v) = diff[v].

            // D[R_v] = D[v] ^ w ^ D[u]
            diff[root_v] = diff[v] ^ w ^ diff[u];

            return true;
        }
    }
};


long long solve(long long n, std::vector<std::vector<long long>> edges) {
    ParityDSU dsu(n);
    long long count = 0;

    for (const auto& edge : edges) {
        // edges[i] = [u_i, v_i, w_i]
        long long u = edge[0];
        long long v = edge[1];
        // w_i is 0 or 1, safe to cast to int for XOR operations
        int w = (int)edge[2]; 

        if (dsu.unite(u, v, w)) {
            count++;
        }
    }

    return count;
}

