        auto [root, root_parity] = find(parent[i]);

        // Update parity[i]: new parity = (i -> old_parent) XOR (old_parent -> root)
        parity[i] = parity[i] ^ root_parity;
        parent[i] = root;

        return {root, parity[i]};
